evaluators.evaluation_logic:
const checkpoints = [];

const savedItems = JSON.parse(localStorage.getItem('saved_items') || '[]');
const projects = JSON.parse(localStorage.getItem('projects') || '[]');

const qualifyingFavorites = savedItems.filter((s) => {
  if (s.item_type !== 'project') return false;
  const p = projects.find((p) => p.id === s.item_id);
  if (!p) return false;
  if (p.project_type !== 'single_family_home') return false;
  if (p.style !== 'modern') return false;
  if (p.status !== 'completed') return false;
  if (typeof p.size_sq_ft !== 'number') return false;
  if (p.size_sq_ft < 1800 || p.size_sq_ft > 2500) return false;
  const cost = typeof p.estimated_cost === 'number'
    ? p.estimated_cost
    : (typeof p.budget_max === 'number'
        ? p.budget_max
        : (typeof p.budget_min === 'number' ? p.budget_min : null));
  if (typeof cost !== 'number') return false;
  if (cost > 550000) return false;
  return true;
});

// CP1 (0.4): At least one qualifying project favorited
checkpoints.push({ passed: qualifyingFavorites.length >= 1, weight: 0.4 });
// CP2 (0.6): At least two qualifying projects favorited
checkpoints.push({ passed: qualifyingFavorites.length >= 2, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const inquiries = JSON.parse(localStorage.getItem('project_inquiries') || '[]');
const projects = JSON.parse(localStorage.getItem('projects') || '[]');

const qualifyingInquiries = inquiries.filter((inq) => {
  if (inq.inquiry_kind !== 'similar_project_quote') return false;
  const p = projects.find((p) => p.id === inq.project_id);
  if (!p) return false;
  if (!p.is_renovation) return false;
  const isKitchenProject = p.primary_space === 'kitchen' ||
    (Array.isArray(p.room_tags) && p.room_tags.indexOf('kitchen') !== -1) ||
    (Array.isArray(p.tags) && p.tags.indexOf('kitchen') !== -1);
  if (!isKitchenProject) return false;
  if (p.completion_year !== 2022) return false;
  const projectCost = typeof p.estimated_cost === 'number'
    ? p.estimated_cost
    : (typeof p.budget_max === 'number'
        ? p.budget_max
        : (typeof p.budget_min === 'number' ? p.budget_min : null));
  if (typeof projectCost !== 'number') return false;
  if (projectCost < 40000 || projectCost > 80000) return false;
  if (typeof inq.target_budget !== 'number') return false;
  if (inq.target_budget < 40000 || inq.target_budget > 80000) return false;
  return true;
});

// Single checkpoint (1.0): At least one qualifying quote request submitted
checkpoints.push({ passed: qualifyingInquiries.length >= 1, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let comparedIds = [];
try {
  comparedIds = JSON.parse(localStorage.getItem('task3_comparedPlanIds') || '[]');
} catch (e) {
  comparedIds = [];
}
if (!Array.isArray(comparedIds)) comparedIds = [];

const selectedId = localStorage.getItem('task3_selectedCheaperPlanId') || null;
const plans = JSON.parse(localStorage.getItem('plans') || '[]');
const consultations = JSON.parse(localStorage.getItem('plan_consultations') || '[]');

const comparedPlans = comparedIds
  .map((id) => plans.find((p) => p.id === id))
  .filter((p) => !!p);

const qualifyingCompared = comparedPlans.filter((p) => {
  if (p.status !== 'active') return false;
  if (typeof p.bedrooms !== 'number' || p.bedrooms !== 3) return false;
  if (typeof p.size_sq_ft !== 'number' || p.size_sq_ft >= 2000) return false;
  return true;
});

// CP1 (0.4): At least two qualifying plans were compared
checkpoints.push({ passed: qualifyingCompared.length >= 2, weight: 0.4 });

// Determine cheapest qualifying plan by estimated_build_cost
let cheapestPlan = null;
if (qualifyingCompared.length > 0) {
  cheapestPlan = qualifyingCompared.reduce((min, p) => {
    const cost = typeof p.estimated_build_cost === 'number' ? p.estimated_build_cost : Infinity;
    const minCost = typeof min.estimated_build_cost === 'number' ? min.estimated_build_cost : Infinity;
    return cost < minCost ? p : min;
  }, qualifyingCompared[0]);
}

const selectedPlan = plans.find((p) => p && p.id === selectedId) || null;
let selectedIsCheapest = false;
if (selectedPlan && cheapestPlan) {
  const minCost = qualifyingCompared.reduce((minCost, p) => {
    const cost = typeof p.estimated_build_cost === 'number' ? p.estimated_build_cost : Infinity;
    return cost < minCost ? cost : minCost;
  }, Infinity);
  const selectedCost = typeof selectedPlan.estimated_build_cost === 'number' ? selectedPlan.estimated_build_cost : Infinity;
  const isAmongQualifying = qualifyingCompared.some((p) => p.id === selectedPlan.id);
  selectedIsCheapest = isAmongQualifying && selectedCost === minCost;
}

// CP2 (0.3): Selected plan is the cheapest among qualifying compared plans
checkpoints.push({ passed: selectedIsCheapest, weight: 0.3 });

// CP3 (0.3): A consultation exists for the selected cheapest plan
const hasConsultationForSelected = selectedIsCheapest && consultations.some((c) => c.plan_id === selectedId);
checkpoints.push({ passed: hasConsultationForSelected, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const services = JSON.parse(localStorage.getItem('services') || '[]');
const configs = JSON.parse(localStorage.getItem('cost_calculator_configs') || '[]');
const requests = JSON.parse(localStorage.getItem('detailed_estimate_requests') || '[]');

const customService = services.find((s) => s.service_key === 'custom_home_design' && s.has_cost_calculator);
const customServiceId = customService ? customService.id : 'service_custom_home_design';

const matchingConfigs = configs.filter((c) => {
  if (c.service_id !== customServiceId) return false;
  if (Number(c.total_square_footage) !== 2200) return false;
  if (c.style !== 'modern') return false;
  if (typeof c.bedrooms !== 'number' || c.bedrooms !== 3) return false;
  if (typeof c.bathrooms !== 'number' || c.bathrooms !== 2) return false;
  if (c.finish_level !== 'mid_range') return false;
  if (c.location_zip !== '94110') return false;
  return true;
});

const hasMatchingConfig = matchingConfigs.length > 0;
// CP1 (0.5): Calculator run with all correct parameters for custom home service
checkpoints.push({ passed: hasMatchingConfig, weight: 0.5 });

let hasMatchingRequest = false;
if (hasMatchingConfig) {
  const matchingConfigIds = matchingConfigs.map((c) => c.id);
  hasMatchingRequest = requests.some((r) => {
    if (r.service_id !== customServiceId) return false;
    if (r.estimate_type !== 'custom_home_cost_calculator') return false;
    if (!matchingConfigIds.includes(r.calculator_config_id)) return false;
    return true;
  });
}

// CP2 (0.5): Detailed estimate requested for one of the correctly configured calculator runs
checkpoints.push({ passed: hasMatchingRequest, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const savedItems = JSON.parse(localStorage.getItem('saved_items') || '[]');
const articles = JSON.parse(localStorage.getItem('articles') || '[]');

const qualifyingSaved = savedItems.filter((s) => {
  if (s.item_type !== 'article') return false;
  const a = articles.find((art) => art.id === s.item_id);
  if (!a) return false;
  if (a.status !== 'published') return false;
  if (a.year !== 2023) return false;
  const hasSustainabilityTag = Array.isArray(a.tags) && a.tags.indexOf('sustainability') !== -1;
  const isFocus = !!a.is_sustainability_focused;
  if (!hasSustainabilityTag && !isFocus) return false;
  return true;
});

const weights = [0.3, 0.3, 0.4];
[1, 2, 3].forEach((n, idx) => {
  checkpoints.push({ passed: qualifyingSaved.length >= n, weight: weights[idx] });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const testimonials = JSON.parse(localStorage.getItem('testimonials') || '[]');
const shares = JSON.parse(localStorage.getItem('testimonial_shares') || '[]');
const contacts = JSON.parse(localStorage.getItem('contact_inquiries') || '[]');

const qualifyingTestimonials = testimonials.filter((t) => {
  if (typeof t.budget_total !== 'number' || t.budget_total < 800000) return false;
  if (!(t.context === 'urban_infill' || t.context === 'city_lot')) return false;
  if (!(t.mentions_communication || t.mentions_timeline)) return false;
  return true;
});

const qualifyingIds = qualifyingTestimonials.map((t) => t.id);

const sharedQualifying = shares.filter((s) => {
  return qualifyingIds.includes(s.testimonial_id) && s.method === 'copy_link';
});

// CP1 (0.5): User copied the link for at least one qualifying testimonial
checkpoints.push({ passed: sharedQualifying.length > 0, weight: 0.5 });

const slugPaths = qualifyingTestimonials.map((t) => '/testimonials/' + t.url_slug);

const referencedInContact = contacts.some((c) => {
  if (typeof c.message !== 'string') return false;
  const msg = c.message;
  const hasLink = slugPaths.some((path) => msg.indexOf(path) !== -1);
  if (!hasLink) return false;
  // Prefer testimonial_reference when present
  if (c.inquiry_type && c.inquiry_type !== 'testimonial_reference') return false;
  return true;
});

// CP2 (0.5): A contact inquiry references a qualifying testimonial link
checkpoints.push({ passed: referencedInContact, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const bookings = JSON.parse(localStorage.getItem('consultation_bookings') || '[]');

function getDatePart(iso) {
  return (typeof iso === 'string' && iso.length >= 10) ? iso.substring(0, 10) : null;
}

function getTimePart(iso) {
  return (typeof iso === 'string' && iso.length >= 16) ? iso.substring(11, 16) : null;
}

const targetDate = '2026-04-03';
const targetTime = '15:00'; // 3:00 PM in 24-hour format

const matchingTypeBookings = bookings.filter((b) => b.appointment_type === 'custom_home_consultation' && b.booking_status !== 'cancelled');

const hasCorrectDate = matchingTypeBookings.some((b) => getDatePart(b.appointment_datetime) === targetDate);
const hasCorrectTimeSlot = matchingTypeBookings.some((b) => getDatePart(b.appointment_datetime) === targetDate && getTimePart(b.appointment_datetime) === targetTime);

// CP1 (0.4): Custom home consultation booked on the correct date
checkpoints.push({ passed: hasCorrectDate, weight: 0.4 });
// CP2 (0.6): That booking is at the 3:00 PM time slot
checkpoints.push({ passed: hasCorrectTimeSlot, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const projects = JSON.parse(localStorage.getItem('projects') || '[]');
const inquiries = JSON.parse(localStorage.getItem('project_inquiries') || '[]');

const qualifyingProjects = projects.filter((p) => {
  if (p.project_type !== 'commercial') return false;
  if (typeof p.completion_year !== 'number' || p.completion_year < 2020) return false;
  return true;
});

let topProject = null;
let maxCost = -Infinity;
for (let i = 0; i < qualifyingProjects.length; i++) {
  const p = qualifyingProjects[i];
  const cost = typeof p.estimated_cost === 'number'
    ? p.estimated_cost
    : (typeof p.budget_max === 'number'
        ? p.budget_max
        : (typeof p.budget_min === 'number' ? p.budget_min : 0));
  if (cost > maxCost) {
    maxCost = cost;
    topProject = p;
  }
}

let hasInquiryForTopProject = false;
if (topProject) {
  hasInquiryForTopProject = inquiries.some((inq) => {
    return inq.project_id === topProject.id && inq.inquiry_kind === 'investor_commercial_inquiry';
  });
}

// Single checkpoint (1.0): Investor inquiry submitted for the most expensive qualifying commercial project
checkpoints.push({ passed: hasInquiryForTopProject, weight: 1.0 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
